def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    mod = Presentation(modified_ppt_path)
    slide_idx = 6
    try:
        mod_slide = mod.slides[slide_idx]
    except IndexError:
        return ("Slide 7 is missing in the modified presentation.", 0.0)

    question_text = "Q: does IP address of host suffice for identifying the process?"
    normalized_question = " ".join(question_text.split())

    # Find the shape with the target question
    target_shape = None
    for shape in mod_slide.shapes:
        if shape.has_text_frame:
            shape_text = shape.text_frame.text
            normalized_shape_text = " ".join(shape_text.split())
            if normalized_question in normalized_shape_text:
                target_shape = shape
                break

    if not target_shape:
        return ("Target question not found on slide 7.", 0.0)

    # Reconstruct text and find where the question starts
    full_text = "".join(p.text for p in target_shape.text_frame.paragraphs)

    # Normalize whitespace to handle cases where newlines are not just single spaces
    normalized_full_text = " ".join(full_text.split())

    if normalized_question not in normalized_full_text:
         return (f"Normalized question not found in shape's text.", 0.0)

    # Find all runs that are part of the question and other paragraphs within the same text box
    question_runs = []
    non_question_runs = []

    for p in target_shape.text_frame.paragraphs:
        p_text_normalized = " ".join(p.text.split())

        # Determine if the paragraph is the question paragraph
        is_question_paragraph = normalized_question in p_text_normalized

        for r in p.runs:
            if is_question_paragraph:
                question_runs.append(r)
            elif r.text.strip():  # Only consider non-empty runs for other paragraphs
                non_question_runs.append(r)

    if not question_runs:
        return ("Could not find any text runs for the question.", 0.0)

    # Check font size for all runs in the question
    for run in question_runs:
        if run.font.size is not None and run.font.size.pt >= 18:
            return (f"Part of the question ('{run.text}') has a font size of {run.font.size.pt}pt, which is not less than 18pt.", 0.0)

    # Check font size for all runs in other paragraphs
    for run in non_question_runs:
        if run.font.size is not None and run.font.size.pt != 24:
            return (f"Part of a non-question paragraph ('{run.text}') has a font size of {run.font.size.pt}pt, which is not 24pt.", 0.0)

    return ("Font size for the entire target question is less than 18pt and other paragraphs are 24pt.", 1.0)

