    orig_img = original_ppt_screenshots[6].image_path
    mod_img = modified_ppt_screenshots[6].image_path

    prompt = (
        "Compare these two images of the same PowerPoint slide. Besides the fact that the second slide reduces the font of the bullet 'Q: does  IP address of host suffice for identifying the process?', there should be no difference between the slide images. "
        "Besides the smaller font size of the single bullet described, are there *any* visible changes to the slide's content, layout, or appearance (such as text, images, shapes, or formatting)? "
        "If there are no visible differences besides the font size, answer NO. Otherwise, answer YES and briefly describe the differences. Take your time, analyze the slides, and compare them carefully."
    )

    vlm_resp = vlm_call(prompt, [orig_img, mod_img], temperature=0.0, max_tokens=128).strip().lower()
    if vlm_resp.startswith('yes'):
        return (f'Extraneous differences found between slides: {vlm_resp}', 0.0)

